compliant:
char password[64];
gets(password);
// use password
memset_s(password, sizeof(password), 0, sizeof(password)); // Compliant: secure clear

volatile char *volatile_clear(volatile char *ptr, size_t len) {
    while (len--) *ptr++ = 0;
    return ptr;
}
void clearSensitiveData() {
    char token[128];
    // ... use token ...
    volatile_clear((volatile char*)token, sizeof(token)); // Compliant
}
